(function(){"use strict";self.onmessage=i=>{const t=i.data,m=(t.rowEnd-t.rowStart)*(t.colEnd-t.colStart),n=new Uint8ClampedArray(m*4);let d=0;const I=t.centerRe,w=t.centerIm,f=t.scaleRe,E=t.scaleIm;let r=0;for(let c=t.rowStart;c<t.rowEnd;c+=1)for(let a=t.colStart;a<t.colEnd;a+=1){const x=I+(a-t.width/2)*f,R=w+(c-t.height/2)*E;let e=0,o=0,s=0;for(;s<t.maxIterations&&e*e+o*o<4;){const h=e*e-o*o+x,p=2*e*o+R;e=h,o=p,s+=1}d+=s;const l=s===t.maxIterations?0:Math.floor(s/t.maxIterations*255);n[r]=l,n[r+1]=l,n[r+2]=l,n[r+3]=255,r+=4}const S={renderId:t.renderId,rowStart:t.rowStart,rowEnd:t.rowEnd,colStart:t.colStart,colEnd:t.colEnd,data:n,steps:d};self.postMessage(S)}})();
